/* %llm_chat: POST to a LOCAL Ollama, schema-constrained, temp0+seed, then JSON-libname parse + allowlist-validate */
%macro llm_chat(model=, sys=, usr=, out=llm_out);
  %global LLM_BASE llm_rc; %let LLM_BASE=http://127.0.0.1:11434;   /* loopback only */
  /* GUARD: refuse any non-loopback endpoint (no egress) */
  %if %sysfunc(prxmatch(/^http:\/\/(127\.0\.0\.1|localhost)\b/i,&LLM_BASE))=0 %then
    %do; %put ERROR:[LLM] non-loopback endpoint blocked: &LLM_BASE; %abort cancel; %end;

  filename _req temp; filename _resp temp; filename _hdr temp;
  /* build the request: stream=false, options.temperature=0+seed, format=JSON SCHEMA (enum-constrained) */
  data _null_; file _req lrecl=30000; length l $28000;
    s=tranwrd(tranwrd("&sys",'\','\\'),'"','\"'); u=tranwrd(tranwrd("&usr",'\','\\'),'"','\"');
    l=cats('{"model":"',"&model",'","stream":false,'
          ,'"options":{"temperature":0,"seed":42,"top_k":1,"top_p":1,"num_predict":512},'
          ,'"format":{"type":"object","properties":{'
          ,'"category":{"type":"string","enum":["ON TRACK","AT RISK","DELAYED"]},'
          ,'"confidence":{"type":"number"},"rationale":{"type":"string"}},'
          ,'"required":["category","confidence","rationale"],"additionalProperties":false},'
          ,'"messages":[{"role":"system","content":"',strip(s),'"},'
          ,'{"role":"user","content":"',strip(u),'"}]}');
    put l;
  run;
  proc http url="&LLM_BASE/api/chat" method="POST" in=_req out=_resp headerout=_hdr ct="application/json";
  run;
  %if &SYS_PROCHTTP_STATUS_CODE ne 200 %then
    %do; %let llm_rc=1; %put ERROR:[LLM] HTTP &SYS_PROCHTTP_STATUS_CODE; %abort cancel; %end;

  /* outer envelope -> message.content is itself a JSON STRING; pull it, then parse again */
  libname _o JSON fileref=_resp;
  data _null_; set _o.message; call symputx('_content', content); run;  /* the schema JSON string */
  libname _o clear;
  filename _c temp; data _null_; file _c; put "&_content"; run;
  libname _p JSON fileref=_c;
  data &out; set _p.root;
    length category $20; category=upcase(category);
    /* VALIDATOR: enum allowlist + range; reject -> fail loud */
    if not indexw('ON TRACK|AT RISK|DELAYED', strip(category), '|')
       then do; put 'ERROR:[LLM] off-allowlist category=' category; call symputx('llm_rc','1'); end;
    if missing(confidence) or confidence<0 or confidence>1
       then do; put 'ERROR:[LLM] confidence out of range=' confidence; call symputx('llm_rc','1'); end;
    model="&model"; endpoint="&LLM_BASE"; seed=42; temperature=0;   /* provenance */
  run;
  libname _p clear; filename _req clear; filename _resp clear; filename _hdr clear; filename _c clear;
  %if &llm_rc=1 %then %do; %put ERROR:[LLM] validation failed - NOT writing tracker; %abort cancel; %end;
%mend llm_chat;
